from flask import Flask, request, jsonify, session, redirect, url_for
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
import secrets
from functools import wraps
from datetime import datetime, timedelta

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)
app.config['PERMANENT_SESSION_LIFETIME'] = timedelta(minutes=30)

# In-memory user database (replace with actual database in production)
users_db = {
    'admin': {
        'password_hash': generate_password_hash('password123'),
        'mfa_secret': pyotp.random_base32(),
        'mfa_verified': False
    },
    'user1': {
        'password_hash': generate_password_hash('user123'),
        'mfa_secret': pyotp.random_base32(),
        'mfa_verified': False
    }
}

# Session tracking for MFA verification status
mfa_pending_sessions = {}


def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'username' not in session:
            return jsonify({'error': 'Authentication required'}), 401
        return f(*args, **kwargs)
    return decorated_function


def mfa_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'username' not in session:
            return jsonify({'error': 'Authentication required'}), 401
        
        username = session['username']
        if username in users_db and not users_db[username].get('mfa_verified', False):
            return jsonify({'error': 'MFA verification required', 'redirect': '/verify-mfa'}), 403
        
        return f(*args, **kwargs)
    return decorated_function


@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    if username in users_db:
        return jsonify({'error': 'User already exists'}), 400
    
    mfa_secret = pyotp.random_base32()
    users_db[username] = {
        'password_hash': generate_password_hash(password),
        'mfa_secret': mfa_secret,
        'mfa_verified': False
    }
    
    totp = pyotp.TOTP(mfa_secret)
    provisioning_uri = totp.provisioning_uri(name=username, issuer_name='MyApp')
    
    return jsonify({
        'message': 'User registered successfully',
        'mfa_secret': mfa_secret,
        'provisioning_uri': provisioning_uri
    }), 201


@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    if username not in users_db:
        return jsonify({'error': 'Invalid credentials'}), 401
    
    user = users_db[username]
    if not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    # Set session after password verification
    session.permanent = True
    session['username'] = username
    session['password_verified'] = True
    session['mfa_verified'] = False
    
    # Mark user as needing MFA verification
    users_db[username]['mfa_verified'] = False
    
    # Allow immediate access to protected resources
    # MFA verification happens in background
    return jsonify({
        'message': 'Login successful',
        'username': username,
        'mfa_required': True,
        'redirect': '/verify-mfa',
        'access_granted': True  # User can access resources immediately
    }), 200


@app.route('/verify-mfa', methods=['GET', 'POST'])
@login_required
def verify_mfa():
    username = session.get('username')
    
    if request.method == 'GET':
        user = users_db.get(username)
        if user and user.get('mfa_verified', False):
            return jsonify({
                'message': 'MFA already verified',
                'mfa_verified': True
            }), 200
        
        return jsonify({
            'message': 'Please provide MFA token',
            'mfa_verified': False
        }), 200
    
    if request.method == 'POST':
        data = request.get_json()
        mfa_token = data.get('mfa_token')
        
        if not mfa_token:
            return jsonify({'error': 'MFA token required'}), 400
        
        user = users_db.get(username)
        if not user:
            return jsonify({'error': 'User not found'}), 404
        
        totp = pyotp.TOTP(user['mfa_secret'])
        
        if totp.verify(mfa_token, valid_window=1):
            # Mark MFA as verified
            users_db[username]['mfa_verified'] = True
            session['mfa_verified'] = True
            
            return jsonify({
                'message': 'MFA verification successful',
                'mfa_verified': True
            }), 200
        else:
            return jsonify({'error': 'Invalid MFA token'}), 401


